```python
def fibonacci(n: int) -> int:
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b
```

```python
def group_by(lst: list, key_fn) -> dict:
    groups = {}
    for item in lst:
        k = key_fn(item)
        groups.setdefault(k, []).append(item)
    return groups
```

